const item = $input.first();
const raw = item.json.stdout.trim();
let parsed;
try {
  parsed = JSON.parse(raw);
} catch(e) {
  throw new Error('Erro ao parsear output do frame: ' + raw);
}
return [{ json: parsed }];

const item = $input.first();
const json = Array.isArray(item.json) ? item.json[0] : item.json;

let rawText = '';
if (json?.output?.[0]?.content?.[0]?.text) {
  rawText = json.output[0].content[0].text;
} else if (json?.content?.[0]?.text) {
  rawText = json.content[0].text;
} else if (typeof json?.text === 'string') {
  rawText = json.text;
} else if (typeof json?.output === 'string') {
  rawText = json.output;
} else if (json?.choices?.[0]?.message?.content) {
  rawText = json.choices[0].message.content;
}

if (!rawText) {
  throw new Error('Texto não encontrado: ' + JSON.stringify(json).substring(0, 300));
}

let cropData;
try {
  cropData = JSON.parse(rawText.replace(/```json|```/g, '').trim());
} catch(e) {
  throw new Error('JSON inválido: ' + rawText);
}

if (typeof cropData.crop === 'undefined') {
  throw new Error('Campo crop ausente: ' + rawText);
}

const tituloExtraido = cropData.titulo_extraido ?? null;

let frameData = null;
for (const fonte of ['Salva URL do Frame', 'Processa Dados do Frame']) {
  try {
    const d = $(fonte).first().json;
    if (d?.video_width && d?.video_height && d?.video_path) { frameData = d; break; }
  } catch(e) {}
}
if (!frameData) throw new Error('frameData não encontrado');

const maxW = Number(frameData.video_width);
const maxH = Number(frameData.video_height);
const totalArea = maxW * maxH;

if (cropData.crop === true) {
  const rawX = Number(cropData.x) || 0;
  const rawY = Number(cropData.y) || 0;
  const rawW = Number(cropData.width) || maxW;
  const rawH = Number(cropData.height) || maxH;

  const rawRatio = (rawW * rawH) / totalArea;
  if (rawRatio > 0.95) {
    return [{ json: {
      crop: false, crop_x: 0, crop_y: 0,
      crop_width: maxW, crop_height: maxH,
      video_path: frameData.video_path,
      frame_path: frameData.frame_path,
      video_width: maxW, video_height: maxH,
      titulo_extraido: tituloExtraido,
      _debug: `crop ignorado — ${(rawRatio*100).toFixed(1)}% do frame`
    }}];
  }

  const safeX = Math.max(0, Math.min(rawX, maxW - 10));
  const safeY = Math.max(0, Math.min(rawY, maxH - 10));
  const fW = Math.min(rawW, maxW - safeX);
  const fH = Math.min(rawH, maxH - safeY);
  const evenW = fW % 2 === 0 ? fW : fW - 1;
  const evenH = fH % 2 === 0 ? fH : fH - 1;

  const clampedRatio = (evenW * evenH) / totalArea;
  if (clampedRatio > 0.95) {
    return [{ json: {
      crop: false, crop_x: 0, crop_y: 0,
      crop_width: maxW, crop_height: maxH,
      video_path: frameData.video_path,
      frame_path: frameData.frame_path,
      video_width: maxW, video_height: maxH,
      titulo_extraido: tituloExtraido,
      _debug: `crop cancelado pós-clamp — ${(clampedRatio*100).toFixed(1)}%`
    }}];
  }

  return [{ json: {
    crop: true,
    crop_x: safeX, crop_y: safeY,
    crop_width: evenW, crop_height: evenH,
    video_path: frameData.video_path,
    frame_path: frameData.frame_path,
    video_width: maxW, video_height: maxH,
    titulo_extraido: tituloExtraido,
    _debug: `crop aplicado — x:${safeX} y:${safeY} w:${evenW} h:${evenH} | ${(clampedRatio*100).toFixed(1)}%`
  }}];
}

return [{ json: {
  crop: false, crop_x: 0, crop_y: 0,
  crop_width: maxW, crop_height: maxH,
  video_path: frameData.video_path,
  frame_path: frameData.frame_path,
  video_width: maxW, video_height: maxH,
  titulo_extraido: tituloExtraido,
  _debug: 'IA indicou sem crop'
}}];

const items = $input.all();
const item = items[0];

let output = item.output || item.json?.output || item.json?.text || '';
output = output.replace(/```json|```/g, '').trim();

let resultado;
try {
  resultado = JSON.parse(output);
} catch (err) {
  throw new Error('❌ JSON inválido da IA: ' + err.message + ' | Raw: ' + output);
}

if (!resultado.titulo || !resultado.legenda) {
  throw new Error('❌ JSON incompleto: ' + JSON.stringify(resultado));
}

return [{
  json: {
    titulo: resultado.titulo,
    legenda: resultado.legenda,
    video_url_s3: $('URL S3 + Transcrição do vídeo + Dados1').first().json.video_url_s3,
    video_clean_path: $('URL S3 + Transcrição do vídeo + Dados1').first().json.video_clean_path
  }
}];

