=<!DOCTYPE html>
<html lang="pt-BR">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=1000" />
  <link href="https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;900&family=Montserrat:wght@400;500;600;700;900&display=swap" rel="stylesheet">
  <style>
    * { margin: 0; padding: 0; box-sizing: border-box; }
    html, body {
      width: 980px;
      min-width: 980px;
      margin: 0;
      padding: 0;
      font-family: 'Inter', sans-serif;
      background: #000000;
    }
    .wrapper {
      width: 980px;
      background: #000000;
      padding: 0;
      display: flex;
      flex-direction: column;
    }
    .top-row {
      display: flex;
      align-items: center;
      justify-content: space-between;
      margin-bottom: 10px;
    }
    .profile {
      display: flex;
      align-items: center;
      gap: 14px;
    }
    .logo-circle {
      width: 72px;
      height: 72px;
      border-radius: 50%;
      background: #1a1a1a;
      border: 2.5px solid #FFD700;
      display: flex;
      align-items: center;
      justify-content: center;
      overflow: hidden;
      flex-shrink: 0;
    }
    .logo-circle img {
      width: 100%;
      height: 100%;
      object-fit: cover;
    }
    .profile-info {
      display: flex;
      flex-direction: column;
      gap: 2px;
    }
    .name-row {
      display: flex;
      align-items: center;
      gap: 10px;
    }
    .empresa-nome {
      color: #FFFFFF;
      font-size: 34px;
      font-weight: 600;
      letter-spacing: -0.3px;
      font-family: 'Inter', sans-serif;
    }
    .verified {
      width: 28px;
      height: 28px;
      background: #1D9BF0;
      border-radius: 50%;
      display: flex;
      align-items: center;
      justify-content: center;
      flex-shrink: 0;
    }
    .verified svg {
      width: 17px;
      height: 17px;
      fill: white;
    }
    .instagram-handle {
      color: #71767B;
      font-size: 22px;
      font-weight: 400;
      font-family: 'Inter', sans-serif;
    }
    .icon-right {
      color: #FFFFFF;
      font-size: 48px;
      font-weight: 900;
      font-family: 'Courier New', monospace;
      align-self: flex-start;
      flex-shrink: 0;
      letter-spacing: -2px;
    }
    .titulo {
      color: #FFFFFF;
      font-size: 38px;
      font-weight: 400;
      line-height: 1.4;
      margin-top: 14px;
      font-family: 'Montserrat', sans-serif;
      word-break: break-word;
      white-space: normal;
      max-width: 980px;
    }
    .titulo .destaque {
      color: #FFD700;
    }
  </style>
</head>
<body>
  <div class="wrapper">
    <div class="top-row">
      <div class="profile">
        <div class="logo-circle">
          <img src="{{ $('When Executed by Another Workflow').first().json.logo_empresa }}" />
        </div>
        <div class="profile-info">
          <div class="name-row">
            <span class="empresa-nome">{{ $('When Executed by Another Workflow').first().json.empresa }}</span>
            <div class="verified">
              <svg viewBox="0 0 24 24"><path d="M9 16.17L4.83 12l-1.42 1.41L9 19 21 7l-1.41-1.41z"/></svg>
            </div>
          </div>
          <span class="instagram-handle">{{ $('When Executed by Another Workflow').first().json.instagram }}</span>
        </div>
      </div>
      <div class="icon-right">&gt;_</div>
    </div>
    <div class="titulo">{{ $('Processa Output da IA1').first().json.titulo }}</div>
  </div>
</body>
</html>
